 426→     *
 427→     * @param activity the calling activity
 428→     * @param site     the site on which the post should be reblogged
 429→     * @param post     the post to be reblogged
 430→     */
 431→    public static void openEditorForReblog(
 432→            Activity activity,
 433→            @Nullable SiteModel site,
 434→            @Nullable ReaderPost post,
 435→            PagePostCreationSourcesDetail reblogSource
 436→    ) {
 437→        if (post == null) {
 438→            ToastUtils.showToast(activity, R.string.post_not_found, ToastUtils.Duration.SHORT);
 439→            return;
 440→        }
 441→
 442→        if (site == null) {
 443→            ToastUtils.showToast(activity, R.string.blog_not_found, ToastUtils.Duration.SHORT);
 444→            return;
 445→        }
 446→
 447→        AnalyticsUtils.trackWithReblogDetails(
 448→            reblogSource == PagePostCreationSourcesDetail.POST_FROM_REBLOG
 449→                    ? READER_ARTICLE_REBLOGGED
 450→                    : READER_ARTICLE_DETAIL_REBLOGGED,
 451→            post.blogId,
 452→            post.postId,
 453→            site.getSiteId()
 454→        );
 455→
 456→        Intent editorIntent = new Intent(activity, EditPostActivity.class);
 457→        editorIntent.putExtra(EditPostActivityConstants.EXTRA_REBLOG_POST_TITLE, post.getTitle());
 458→        editorIntent.putExtra(EditPostActivityConstants.EXTRA_REBLOG_POST_QUOTE, post.getExcerpt());
 459→        editorIntent.putExtra(EditPostActivityConstants.EXTRA_REBLOG_POST_IMAGE, post.getFeaturedImage());
 460→        editorIntent.putExtra(EditPostActivityConstants.EXTRA_REBLOG_POST_CITATION, post.getUrl());
 461→        editorIntent.setAction(EditPostActivityConstants.ACTION_REBLOG);
 462→
 463→        addNewPostForResult(editorIntent, activity, site, false, reblogSource, -1, null);
 464→    }
