1531→     * open the passed url in the device's external browser
1532→     */
1533→    public static void openUrlExternal(Context context, @NonNull String url) {
1534→        Uri uri = Uri.parse(url);
1535→        Intent intent = new Intent(Intent.ACTION_VIEW, uri);
1536→        intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK);
1537→
1538→        try {
1539→            // Disable deeplinking activity so to not catch WP URLs.
1540→            // We'll re-enable them later - see callers of WPActivityUtils#enableReaderDeeplinks.
1541→            WPActivityUtils.disableReaderDeeplinks(context);
1542→
1543→            context.startActivity(intent);
1544→        } catch (ActivityNotFoundException e) {
1545→            ToastUtils.showToast(context, context.getString(R.string.cant_open_url), ToastUtils.Duration.LONG);
1546→            AppLog.e(AppLog.T.UTILS, "No default app available on the device to open the link: " + url, e);
1547→        } catch (SecurityException se) {
1548→            AppLog.e(AppLog.T.UTILS, "Error opening url in default browser. Url: " + url, se);
1549→
1550→            List<ResolveInfo> infos = context.getPackageManager().queryIntentActivities(intent, 0);
1551→            if (infos.size() == 1) {
1552→                // there's only one handler and apparently it caused the exception so, just inform and bail
1553→                AppLog.d(AppLog.T.UTILS, "Only one url handler found so, bailing.");
1554→                ToastUtils.showToast(context, context.getString(R.string.cant_open_url));
1555→            } else {
1556→                Intent chooser = Intent.createChooser(intent, context.getString(R.string.error_please_choose_browser));
1557→                context.startActivity(chooser);
1558→            }
1559→        }
1560→    }
