894→    private void handleOpenPageIntent(@NonNull Intent intent) {
895→        showOpenPageMessageIfNeeded();
896→        String pagePosition = intent.getStringExtra(ARG_OPEN_PAGE);
897→        if (!TextUtils.isEmpty(pagePosition)) {
898→            switch (pagePosition) {
899→                case ARG_MY_SITE:
900→                    if (mBottomNav != null) mBottomNav.setCurrentSelectedPage(PageType.MY_SITE);
901→                    break;
902→                case ARG_NOTIFICATIONS:
903→                    setUpMainView();
904→                    if (mJetpackFeatureRemovalPhaseHelper.shouldRemoveJetpackFeatures()) {
905→                        Map<String, String> trackingProperties = new HashMap<>();
906→                        trackingProperties.put("calling_function", "deeplink_notifications");
907→                        showJetpackFeatureOverlayAccessedInCorrectly(trackingProperties);
908→                        break;
909→                    }
910→                    if (mBottomNav != null) mBottomNav.setCurrentSelectedPage(PageType.NOTIFS);
911→                    break;
912→                case ARG_READER:
913→                    setUpMainView();
914→                    if (mJetpackFeatureRemovalPhaseHelper.shouldRemoveJetpackFeatures()) {
915→                        Map<String, String> trackingProperties = new HashMap<>();
916→                        trackingProperties.put("calling_function", "deeplink_reader");
917→                        showJetpackFeatureOverlayAccessedInCorrectly(trackingProperties);
918→                        break;
919→                    }
920→                    if (intent.getBooleanExtra(ARG_READER_BOOKMARK_TAB, false) && mBottomNav != null && mBottomNav
921→                            .getActiveFragment() instanceof ReaderFragment) {
922→                        ((ReaderFragment) mBottomNav.getActiveFragment()).requestBookmarkTab();
923→                    } else {
924→                        if (mBottomNav != null) mBottomNav.setCurrentSelectedPage(PageType.READER);
925→                    }
926→                    break;
927→                case ARG_EDITOR:
928→                    if (!mSelectedSiteRepository.hasSelectedSite()) {
929→                        initSelectedSite();
930→                    }
931→                    final int promptId = intent.getIntExtra(ARG_EDITOR_PROMPT_ID, -1);
932→                    final EntryPoint entryPoint = (EntryPoint) intent.getSerializableExtra(ARG_EDITOR_ORIGIN);
933→                    onNewPostButtonClicked(promptId, entryPoint);
934→                    break;
935→                case ARG_STATS:
936→                    if (!mSelectedSiteRepository.hasSelectedSite()) {
937→                        initSelectedSite();
938→                    }
939→                    if (mJetpackFeatureRemovalPhaseHelper.shouldRemoveJetpackFeatures()) {
940→                        Map<String, String> trackingProperties = new HashMap<>();
941→                        trackingProperties.put("calling_function", "deeplink_stats");
942→                        showJetpackFeatureOverlayAccessedInCorrectly(trackingProperties);
943→                        break;
944→                    }
945→                    if (mJetpackFeatureRemovalPhaseHelper.shouldShowStaticPage()) {
946→                        ActivityLauncher.showJetpackStaticPoster(this);
947→                        break;
948→                    }
949→                    if (intent.hasExtra(ARG_STATS_TIMEFRAME)) {
950→                        ActivityLauncher.viewBlogStatsForTimeframe(this, getSelectedSite(),
951→                                (StatsTimeframe) intent.getSerializableExtra(ARG_STATS_TIMEFRAME),
952→                                StatsLaunchedFrom.LINK);
953→                    } else {
954→                        ActivityLauncher.viewBlogStats(this, getSelectedSite(), StatsLaunchedFrom.LINK);
955→                    }
956→                    break;
957→                case ARG_PAGES:
958→                    if (!mSelectedSiteRepository.hasSelectedSite()) {
959→                        initSelectedSite();
960→                    }
961→                    ActivityLauncher.viewCurrentBlogPages(this, getSelectedSite());
962→                    break;
963→                case ARG_WP_COM_SIGN_UP:
964→                    ActivityLauncher.showSignInForResultWpComOnly(this);
965→                    break;
966→                case ARG_BLOGGING_PROMPTS_ONBOARDING:
967→                    showBloggingPromptsOnboarding();
968→                    break;
969→                case ARG_MEDIA:
970→                    if (!mSelectedSiteRepository.hasSelectedSite()) {
971→                        initSelectedSite();
972→                    }
973→                    mActivityNavigator.viewCurrentBlogMedia(this, getSelectedSite());
974→                    break;
975→            }
976→        } else {
977→            AppLog.e(T.MAIN, "WPMainActivity.handleOpenIntent called with an invalid argument.");
978→        }
979→    }
