1113→
1114→    private static void browsePostOrPageEx(
1115→            Context context,
1116→            SiteModel site,
1117→            PostImmutableModel post,
1118→            RemotePreviewType remotePreviewType) {
1119→        if (site == null || post == null || TextUtils.isEmpty(post.getLink())) {
1120→            return;
1121→        }
1122→
1123→        if (remotePreviewType == RemotePreviewType.REMOTE_PREVIEW_WITH_REMOTE_AUTO_SAVE
1124→                        && TextUtils.isEmpty(post.getAutoSavePreviewUrl())) {
1125→            return;
1126→        }
1127→
1128→        String url = PostUtils.getPreviewUrlForPost(remotePreviewType, post);
1129→
1130→        String shareableUrl = post.getLink();
1131→        String shareSubject = post.getTitle();
1132→        boolean startPreviewForResult = remotePreviewType != RemotePreviewType.NOT_A_REMOTE_PREVIEW;
1133→
1134→        if (site.isWPCom()) {
1135→            WPWebViewActivity.openPostUrlByUsingGlobalWPCOMCredentials(
1136→                    context,
1137→                    url,
1138→                    shareableUrl,
1139→                    shareSubject,
1140→                    true,
1141→                    startPreviewForResult);
1142→        } else if (site.isWPComAtomic() && !site.isPrivateWPComAtomic()) {
1143→            openAtomicBlogPostPreview(
1144→                    context,
1145→                    url,
1146→                    site.getLoginUrl(),
1147→                    site.getFrameNonce());
1148→        } else if (site.isJetpackConnected() && site.isUsingWpComRestApi()) {
1149→            WPWebViewActivity
1150→                    .openJetpackBlogPostPreview(
1151→                            context,
1152→                            url,
1153→                            shareableUrl,
1154→                            shareSubject,
1155→                            site.getFrameNonce(),
1156→                            true,
1157→                            startPreviewForResult,
1158→                            site.isPrivateWPComAtomic() ? site.getSiteId() : 0);
1159→        } else {
1160→            // Add the original post URL to the list of allowed URLs.
1161→            // This is necessary because links are disabled in the webview, but WP removes "?preview=true"
1162→            // from the passed URL, and internally redirects to it. EX:Published posts on a site with Plain
1163→            // permalink structure settings.
1164→            // Ref: https://github.com/wordpress-mobile/WordPress-Android/issues/4873
1165→            WPWebViewActivity.openUrlByUsingBlogCredentials(
1166→                    context,
1167→                    site,
1168→                    post,
1169→                    url,
1170→                    new String[]{post.getLink()},
1171→                    true,
1172→                    true,
1173→                    startPreviewForResult);
1174→        }
1175→    }
1176→
1177→    private static void openAtomicBlogPostPreview(Context context, String url, String authenticationUrl,
1178→                                                 String frameNonce) {
1179→        try {
1180→            Intent intent = new Intent(Intent.ACTION_VIEW);
1181→            intent.setData(Uri.parse(authenticationUrl + "?redirect_to=" + URLEncoder
1182→                    .encode(url + "&frame-nonce=" + UrlUtils.urlEncode(frameNonce), ENCODING_UTF8)));
1183→            context.startActivity(intent);
1184→        } catch (UnsupportedEncodingException e) {
1185→            e.printStackTrace();
1186→        }
1187→    }
