1562→    public static void openStatsUrl(Context context, @NonNull String url) {
1563→        if (url.startsWith("https://wordpress.com/my-stats") || url.startsWith("http://wordpress.com/my-stats")) {
1564→            // make sure to load the no-chrome version of Stats over https
1565→            url = UrlUtils.makeHttps(url);
1566→            if (url.contains("?")) {
1567→                // add the no chrome parameters if not available
1568→                if (!url.contains("?no-chrome") && !url.contains("&no-chrome")) {
1569→                    url += "&no-chrome";
1570→                }
1571→            } else {
1572→                url += "?no-chrome";
1573→            }
1574→            WPWebViewActivity.openUrlByUsingGlobalWPCOMCredentials(context, url);
1575→        } else if (url.startsWith("https") || url.startsWith("http")) {
1576→            WPWebViewActivity.openURL(context, url);
1577→        }
1578→    }
