102→    private fun StatsFragmentBinding.initializeViews() {
103→        statsTrafficTabEnabled = mStatsTrafficSubscribersTabFeatureConfig.isEnabled()
104→
105→        val adapter = StatsPagerAdapter(this@StatsFragment)
