207→    private fun StatsFragmentBinding.updateUi(statsModuleUiModel: StatsModuleUiModel) {
208→        if (statsModuleUiModel.disabledStatsViewVisible) {
209→            disabledView.statsDisabledView.visibility = View.VISIBLE
210→            tabLayout.visibility = View.GONE
211→            pullToRefresh.visibility = View.GONE
212→
213→            if (statsModuleUiModel.disabledStatsProgressVisible) {
214→                disabledView.statsDisabledView.progressBar.visibility = View.VISIBLE
215→                disabledView.statsDisabledView.button.visibility = View.GONE
216→            } else {
217→                disabledView.statsDisabledView.progressBar.visibility = View.GONE
218→                disabledView.statsDisabledView.button.visibility = View.VISIBLE
219→            }
220→        } else {
221→            disabledView.statsDisabledView.visibility = View.GONE
222→            tabLayout.visibility = View.VISIBLE
223→            pullToRefresh.visibility = View.VISIBLE
224→        }
225→    }
