279→    private fun showSnackbar(
280→        activity: FragmentActivity,
281→        holder: SnackbarMessageHolder?
282→    ) {
283→        val parent = activity.findViewById<View>(R.id.coordinatorLayout)
284→        if (holder != null && parent != null) {
285→            if (holder.buttonTitle == null) {
286→                WPSnackbar.make(
287→                    parent,
288→                    uiHelpers.getTextOfUiString(requireContext(), holder.message),
289→                    Snackbar.LENGTH_LONG
290→                ).show()
291→            } else {
292→                val snackbar = WPSnackbar.make(
293→                    parent,
294→                    uiHelpers.getTextOfUiString(requireContext(), holder.message),
295→                    Snackbar.LENGTH_LONG
296→                )
297→                snackbar.setAction(uiHelpers.getTextOfUiString(requireContext(), holder.buttonTitle)) {
298→                    holder.buttonAction()
299→                }
300→                snackbar.show()
301→            }
302→        }
303→    }
