896→        String pagePosition = intent.getStringExtra(ARG_OPEN_PAGE);
897→        if (!TextUtils.isEmpty(pagePosition)) {
898→            switch (pagePosition) {
899→                case ARG_MY_SITE:
900→                    if (mBottomNav != null) mBottomNav.setCurrentSelectedPage(PageType.MY_SITE);
901→                    break;
902→                case ARG_NOTIFICATIONS:
903→                    setUpMainView();
904→                    if (mJetpackFeatureRemovalPhaseHelper.shouldRemoveJetpackFeatures()) {
905→                        Map<String, String> trackingProperties = new HashMap<>();
906→                        trackingProperties.put("calling_function", "deeplink_notifications");
907→                        showJetpackFeatureOverlayAccessedInCorrectly(trackingProperties);
908→                        break;
909→                    }
910→                    if (mBottomNav != null) mBottomNav.setCurrentSelectedPage(PageType.NOTIFS);
911→                    break;
912→                case ARG_READER:
913→                    setUpMainView();
914→                    if (mJetpackFeatureRemovalPhaseHelper.shouldRemoveJetpackFeatures()) {
915→                        Map<String, String> trackingProperties = new HashMap<>();
916→                        trackingProperties.put("calling_function", "deeplink_reader");
917→                        showJetpackFeatureOverlayAccessedInCorrectly(trackingProperties);
918→                        break;
919→                    }
920→                    if (intent.getBooleanExtra(ARG_READER_BOOKMARK_TAB, false) && mBottomNav != null && mBottomNav
921→                            .getActiveFragment() instanceof ReaderFragment) {
922→                        ((ReaderFragment) mBottomNav.getActiveFragment()).requestBookmarkTab();
923→                    } else {
924→                        if (mBottomNav != null) mBottomNav.setCurrentSelectedPage(PageType.READER);
