926→                    break;
927→                case ARG_EDITOR:
928→                    if (!mSelectedSiteRepository.hasSelectedSite()) {
929→                        initSelectedSite();
930→                    }
931→                    final int promptId = intent.getIntExtra(ARG_EDITOR_PROMPT_ID, -1);
932→                    final EntryPoint entryPoint = (EntryPoint) intent.getSerializableExtra(ARG_EDITOR_ORIGIN);
933→                    onNewPostButtonClicked(promptId, entryPoint);
